#include <iostream>

using namespace std;

int fib(int n)
{
    if (n <= 1) return n;

    int prev2 = 0, prev1 = 1;
    for (int i = 2; i <= n; i++)
    {
        int current = prev1 + prev2;
        prev2 = prev1;
        prev1 = current;
    }

    return prev1;
}

int main()
{
    cout << fib(4) << endl;

    return 0;
}

#include <iostream>

using namespace std;

double myPow(double x, long n)
{
    if (n == 0) return 1.0;
    if (n < 0) return 1.0 / myPow(x, -n);

    return x * myPow(x, n - 1);
}

int main()
{
    cout << myPow(2.0, 10) << endl;

    return 0;
}

#include <iostream>

using namespace std;

double fastPow(double x, long n)
{
    if (n == 0) return 1.0;

    double half = fastPow(x, n / 2);

    if (n % 2 == 0) return half * half;
    return half * half * x;
}

double myPow(double x, int n)
{
    long N = n;
    if (N < 0) return 1.0 / fastPow(x, -N);
    return fastPow(x, N);
}

int main()
{
    cout << myPow(2.0, 10) << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* reverseList(ListNode* head)
{
    vector<int> values;
    for (ListNode* cur = head; cur; cur = cur->next) values.push_back(cur->val);

    ListNode* cur = head;
    for (int i = values.size() - 1; i >= 0; i--)
    {
        cur->val = values[i];
        cur = cur->next;
    }

    return head;
}

int main()
{
    ListNode* head = new ListNode(1);
    head->next = new ListNode(2);
    head->next->next = new ListNode(3);

    reverseList(head);
    for (ListNode* n = head; n; n = n->next) cout << n->val << " ";

    return 0;
}

#include <iostream>

using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* reverseList(ListNode* head)
{
    if (head == nullptr || head->next == nullptr) return head; // base case

    ListNode* newHead = reverseList(head->next);

    head->next->next = head; // point the next node back at this one
    head->next = nullptr;

    return newHead;
}

int main()
{
    ListNode* head = new ListNode(1);
    head->next = new ListNode(2);
    head->next->next = new ListNode(3);

    ListNode* newHead = reverseList(head);
    for (ListNode* n = newHead; n; n = n->next) cout << n->val << " ";

    return 0;
}

